const seen = new Set();
const seenTitles = new Set();
const out = [];

for (const item of $input.all()) {
  const url = item.json.link || item.json.url || item.json.guid || item.json.id;

  // Normalise le titre pour dedup sémantique
  const rawTitle = item.json.title || '';
  const normalizedTitle = rawTitle
    .toLowerCase()
    .replace(/[^\w\s]/g, '')    // enlève ponctuation
    .replace(/\s+/g, ' ')        // normalise espaces
    .trim()
    .substring(0, 60);            // prend les 60 premiers chars (le vrai signal)

  // Skip si URL OU titre-normalisé déjà vu
  if (seen.has(url) || seenTitles.has(normalizedTitle)) continue;

  seen.add(url);
  seenTitles.add(normalizedTitle);
  out.push(item);
}

return out;

// Limiter à 30 articles max pour ne pas exploser le TPM Groq
const items = $input.all().slice(0, 30);

const articles = items.map(item => {
  const title = item.json.title || 'Sans titre';
  const link = item.json.link || item.json.url || '';
  // Réduit la description à 150 chars pour économiser des tokens
  const desc = (item.json.contentSnippet || item.json.description || '').substring(0, 150);
  return `- ${title}\n  ${desc}\n  ${link}`;
}).join('\n\n');

return [{ json: { articles_text: articles } }];

let text = $input.first().json.output || $input.first().json.message?.content || $input.first().json.text || '';

// Supprime le préambule
text = text.replace(/^([\s\S]*?)(?=\n[•🚨<])/, '');

// Supprime la conclusion
text = text.replace(/\n*(Let me know|Would you like|This message was|Feel free).*$/si, '');

// Convertit Markdown en HTML AVANT la protection
text = text.replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
text = text.replace(/\*(.*?)\*/g, '<i>$1</i>');
text = text.replace(/\[(.*?)\]\((https?:\/\/.*?)\)/g, '<a href="$2">$1</a>');

// PROTECTION : isole les vraies balises avec des placeholders
text = text.replace(/<(\/?b)>/gi, '%%B$1B%%');
text = text.replace(/<(\/?i)>/gi, '%%I$1I%%');
text = text.replace(/<a href="(.*?)">(.*?)<\/a>/gi, '%%A$1A$2AA%%');

// NUCLEAIRE : supprime TOUS les < et > restants
text = text.replace(/[<>]/g, '');

// RESTAURATION : remet les vraies balises
text = text.replace(/%%B(\/?b)B%%/gi, '<$1>');
text = text.replace(/%%I(\/?i)I%%/gi, '<$1>');
text = text.replace(/%%A(.*?)A(.*?)AA%%/g, '<a href="$1">$2</a>');

// Nettoie les crochets orphelins
text = text.replace(/\[(.*?)\]/g, '$1');

// Limite à 4000 chars
if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n... (tronqué)';
}
text = text.trimStart();
if (!text.startsWith('<b>')) text = '<b>🌍 Géopolitique & Conflits</b>\n' + text;

return [{ json: { clean_text: `🌍 <b><a href="https://linktr.ee/kwce">kwce</a> WORLD DIGEST</b>\n\n${text}\n\n━━━━━━━━━━━━━━━\nPropulsé par <a href="https://linktr.ee/kwce">kwce</a>` } }];

